import sqlite3, pickle, base64, zlib
db = sqlite3.connect('/var/www/gmao/gmao.db')
db.row_factory = sqlite3.Row
raw = base64.b64decode('')
data = pickle.loads(zlib.decompress(raw))
specs_list = data['specs']
for i,nom in enumerate(specs_list):
    db.execute("INSERT OR IGNORE INTO astreinte_specialites (nom,ordre) VALUES (?,?)",(nom,i))
db.commit()
specs = {r['nom']:r['id'] for r in db.execute("SELECT id,nom FROM astreinte_specialites").fetchall()}
count = 0
for date_str, day in data['data'].items():
    for nom, tech in day.items():
        sid = specs.get(nom)
        if sid:
            db.execute("INSERT INTO astreinte_planning(date,specialite_id,technicien)VALUES(?,?,?)ON CONFLICT(date,specialite_id)DO UPDATE SET technicien=?",(date_str,sid,tech,tech))
            count += 1
db.commit()
print(f"Importé: {count} entrées")
